@app.route('/api/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body is required'}), 400

        username = sanitize_string(data.get('username', ''), max_length=50)
        email = sanitize_string(data.get('email', ''), max_length=255)
        password = data.get('password', '')
        display_name = sanitize_string(data.get('display_name', ''), max_length=100)

        if not username or not email or not password:
            return jsonify({'error': 'Username, email, and password are required'}), 400

        if not re.match(r'^[a-zA-Z0-9_]{3,50}$', username):
            return jsonify({'error': 'Username must be 3-50 alphanumeric characters or underscores'}), 400

        if not validate_email(email):
            return jsonify({'error': 'Invalid email format'}), 400

        is_valid, msg = validate_password(password)
        if not is_valid:
            return jsonify({'error': msg}), 400

        salt, hashed_password = hash_password(password)

        user = {
            'username': username,
            'email': email.lower(),
            'password_hash': hashed_password,
            'password_salt': salt,
            'display_name': display_name or username,
            'role': 'user',
            'bio': '',
            'avatar_url': '',
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow(),
            'is_active': True,
            'document_count': 0
        }

        db = get_db()
        result = db.users.insert_one(user)

        token = generate_token(result.inserted_id, username, 'user')

        return jsonify({
            'message': 'User registered successfully',
            'user_id': str(result.inserted_id),
            'token': token
        }), 201

    except DuplicateKeyError:
        return jsonify({'error': 'Username or email already exists'}), 409
    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


