@app.route('/api/documents', methods=['POST'])
@token_required
def create_document():
    """Create a new document."""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body is required'}), 400

        title = sanitize_string(data.get('title', ''), max_length=200)
        content = sanitize_string(data.get('content', ''), max_length=100000)
        tags = data.get('tags', [])
        category = sanitize_string(data.get('category', ''), max_length=50)
        status = sanitize_string(data.get('status', 'draft'), max_length=20)

        if not title:
            return jsonify({'error': 'Title is required'}), 400

        if not content:
            return jsonify({'error': 'Content is required'}), 400

        if status not in ('draft', 'published', 'archived'):
            return jsonify({'error': 'Status must be draft, published, or archived'}), 400

        # Sanitize tags
        if not isinstance(tags, list):
            return jsonify({'error': 'Tags must be a list'}), 400
        sanitized_tags = []
        for tag in tags[:20]:  # Limit to 20 tags
            t = sanitize_string(str(tag), max_length=50)
            if t:
                sanitized_tags.append(t.lower())
        sanitized_tags = list(set(sanitized_tags))

        user_id = validate_object_id(g.current_user['user_id'])
        if not user_id:
            return jsonify({'error': 'Invalid user ID'}), 400

        document = {
            'title': title,
            'content': content,
            'tags': sanitized_tags,
            'category': category,
            'status': status,
            'author_id': user_id,
            'author_username': g.current_user['username'],
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow(),
            'views': 0,
            'likes': 0,
            'metadata': {}
        }

        # Allow custom metadata
        if 'metadata' in data and isinstance(data['metadata'], dict):
            clean_metadata = sanitize_query_value(data['metadata'])
            if clean_metadata:
                document['metadata'] = clean_metadata

        db = get_db()
        result = db.documents.insert_one(document)

        # Update user document count
        db.users.update_one(
            {'_id': user_id},
            {'$inc': {'document_count': 1}}
        )

        return jsonify({
            'message': 'Document created successfully',
            'document_id': str(result.inserted_id)
        }), 201

    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


