# --- Aggregation Pipeline Routes ---

@app.route('/api/analytics/documents-by-category', methods=['GET'])
@token_required
def documents_by_category():
    """Aggregate documents by category."""
    try:
        db = get_db()

        pipeline = [
            {'$match': {'status': 'published'}},
            {'$group': {
                '_id': '$category',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'avg_views': {'$avg': '$views'}
            }},
            {'$sort': {'count': -1}},
            {'$project': {
                'category': '$_id',
                'count': 1,
                'total_views': 1,
                'total_likes': 1,
                'avg_views': {'$round': ['$avg_views', 2]},
                '_id': 0
            }}
        ]

        results = list(db.documents.aggregate(pipeline))

        return jsonify({'categories': results}), 200

    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


