@app.route('/api/analytics/documents-over-time', methods=['GET'])
@token_required
def documents_over_time():
    """Get document creation trends over time."""
    try:
        granularity = sanitize_string(request.args.get('granularity', 'month'), max_length=10)
        if granularity not in ('day', 'week', 'month', 'year'):
            granularity = 'month'

        db = get_db()

        if granularity == 'day':
            date_format = '%Y-%m-%d'
            date_group = {
                'year': {'$year': '$created_at'},
                'month': {'$month': '$created_at'},
                'day': {'$dayOfMonth': '$created_at'}
            }
        elif granularity == 'week':
            date_format = '%Y-W%U'
            date_group = {
                'year': {'$year': '$created_at'},
                'week': {'$week': '$created_at'}
            }
        elif granularity == 'year':
            date_format = '%Y'
            date_group = {
                'year': {'$year': '$created_at'}
            }
        else:  # month
            date_format = '%Y-%m'
            date_group = {
                'year': {'$year': '$created_at'},
                'month': {'$month': '$created_at'}
            }

        pipeline = [
            {'$group': {
                '_id': date_group,
                'count': {'$sum': 1},
                'published': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'drafts': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'draft']}, 1, 0]}
                }
            }},
            {'$sort': {'_id': 1}},
            {'$project': {
                'period': '$_id',
                'count': 1,
                'published': 1,
                'drafts': 1,
                '_id': 0
            }}
        ]

        results = list(db.documents.aggregate(pipeline))

        return jsonify({
            'granularity': granularity,
            'data': results
        }), 200

    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


@app.route('/api/analytics/content-stats', methods=['GET'])
@token_required
def content_stats():
    """Get overall content statistics."""
    try:
        db = get_db()

        pipeline = [
            {'$facet': {
                'total_stats': [
                    {'$group': {
                        '_id': None,
                        'total_documents': {'$sum': 1},
                        'total_views': {'$sum': '$views'},
                        'total_likes': {'$sum': '$likes'},
                        'avg_views': {'$avg': '$views'},
                        'avg_likes': {'$avg': '$likes'}
                    }}
                ],
                'by_status': [
                    {'$group': {
                        '_id': '$status',
                        'count': {'$sum': 1}
                    }}
                ],
                'recent_documents': [
                    {'$sort': {'created_at': -1}},
                    {'$limit': 5},
                    {'$project': {
                        'title': 1,
                        'author_username': 1,
                        'status': 1,
                        'created_at': 1,
                        'views': 1
                    }}
                ],
                'most_viewed': [
                    {'$match': {'status': 'published'}},
                    {'$sort': {'views': -1}},
                    {'$limit': 5},
                    {'$project': {
                        'title': 1,
                        'author_username': 1,
                        'views': 1,
                        'likes': 1
                    }}
                ]
            }}
        ]

        results = list(db.documents.aggregate(pipeline))

        if results:
            result = results[0]

            # Clean up total stats
            total_stats = result.get('total_stats', [{}])
            if total_stats:
                stats = total_stats[0]
                stats.pop('_id', None)
                if 'avg_views' in stats:
                    stats['avg_views'] = round(stats['avg_views'], 2)
                if 'avg_likes' in stats:
                    stats['avg_likes'] = round(stats['avg_likes'], 2)
            else:
                stats = {
                    'total_documents': 0,
                    'total_views': 0,
                    'total_likes': 0,
                    'avg_views': 0,
                    'avg_likes': 0
                }

            # Clean up status breakdown
            status_breakdown = {}
            for item in result.get('by_status', []):
                status_breakdown[item['_id']] = item['count']

            # Clean up recent and most viewed
            for doc in result.get('recent_documents', []):
                doc['_id'] = str(doc['_id'])
                if 'created_at' in doc:
                    doc['created_at'] = doc['created_at'].isoformat()

            for doc in result.get('most_viewed', []):
                doc['_id'] = str(doc['_id'])

            return jsonify({
                'stats': stats,
                'status_breakdown': status_breakdown,
                'recent_documents': result.get('recent_documents', []),
                'most_viewed': result.get('most_viewed', [])
            }), 200

        return jsonify({'stats': {}, 'status_breakdown': {}, 'recent_documents': [], 'most_viewed': []}), 200

    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


@app.route('/api/analytics/author-stats', methods=['GET'])
@token_required
def author_stats():
    """Get statistics for the current user's content."""
    try:
        user_id = validate_object_id(g.current_user['user_id'])
        if not user_id:
            return jsonify({'error': 'Invalid user ID'}), 400

        db = get_db()

        pipeline = [
            {'$match': {'author_id': user_id}},
            {'$facet': {
                'overview': [
                    {'$group': {
                        '_id': None,
                        'total_documents': {'$sum': 1},
                        'total_views': {'$sum': '$views'},
                        'total_likes': {'$sum': '$likes'},
                        'avg_views': {'$avg': '$views'}
                    }}
                ],
                'by_status': [
                    {'$group': {
                        '_id': '$status',
                        'count': {'$sum': 1}
                    }}
                ],
                'by_category': [
                    {'$group': {
                        '_id': '$category',
                        'count': {'$sum': 1},
                        'views': {'$sum': '$views'}
                    }},
                    {'$sort': {'count': -1}}
                ],
                'top_performing': [
                    {'$match': {'status': 'published'}},
                    {'$sort': {'views': -1}},
                    {'$limit': 5},
                    {'$project': {
                        'title': 1,
                        'views': 1,
                        'likes': 1,
                        'created_at': 1
                    }}
                ]
            }}
        ]

        results = list(db.documents.aggregate(pipeline))

        if results:
            result = results[0]

            overview = result.get('overview', [{}])
            if overview:
                stats = overview[0]
                stats.pop('_id', None)
                if 'avg_views' in stats:
                    stats['avg_views'] = round(stats['avg_views'], 2)
            else:
                stats = {
                    'total_documents': 0,
                    'total_views': 0,
                    'total_likes': 0,
                    'avg_views': 0
                }

            status_breakdown = {}
            for item in result.get('by_status', []):
                status_breakdown[item['_id']] = item['count']

            categories = []
            for item in result.get('by_category', []):
                categories.append({
                    'category': item['_id'],
                    'count': item['count'],
                    'views': item['views']
                })

            top_performing = []
            for doc in result.get('top_performing', []):
                doc['_id'] = str(doc['_id'])
                if 'created_at' in doc:
                    doc['created_at'] = doc['created_at'].isoformat()
                top_performing.append(doc)

            return jsonify({
                'overview': stats,
                'status_breakdown': status_breakdown,
                'categories': categories,
                'top_performing': top_performing
            }), 200

        return jsonify({
            'overview': {},
            'status_breakdown': {},
            'categories': [],
            'top_performing': []
        }), 200

    except PyMongoError:
        return jsonify({'error': 'Database error occurred'}), 500


